import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";

export default function PaymentSystem() {

  const [payments, setPayments] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [file, setFile] = useState(null);
  const [editId, setEditId] = useState(null);

  const [form, setForm] = useState({
    title: "",
    clientName: "",
    projectName: "",
    milestoneName: "",
    totalAmount: "",
    paidAmount: "",
    pendingAmount: "",
    paymentDate: "",
    dueDate: ""
  });

  const onlyLetters = /^[A-Za-z\s]*$/;
  const onlyNumbers = /^[0-9]*$/;

  useEffect(() => {
    loadPayments();
  }, []);

  const loadPayments = async () => {
    const res = await fetch("http://localhost:5000/api/payments");
    const data = await res.json();
    setPayments(data);
  };

  // ================= CHANGE
  const handleChange = (e) => {
    const { name, value } = e.target;

    if (["title", "clientName", "projectName", "milestoneName"].includes(name)) {
      if (!onlyLetters.test(value)) return;
    }

    if (["totalAmount", "paidAmount"].includes(name)) {
      if (!onlyNumbers.test(value)) return;

      const updated = { ...form, [name]: value };

      updated.pendingAmount =
        Number(updated.totalAmount || 0) -
        Number(updated.paidAmount || 0);

      setForm(updated);
      return;
    }

    setForm({ ...form, [name]: value });
  };

  // ================= SAVE / UPDATE
  const savePayment = async (e) => {
    e.preventDefault();

    const fd = new FormData();
    Object.keys(form).forEach(k => fd.append(k, form[k]));
    if (file) fd.append("invoice", file);

    const url = editId
      ? `http://localhost:5000/api/payments/${editId}`
      : "http://localhost:5000/api/payments";

    const method = editId ? "PUT" : "POST";

    await fetch(url, {
      method,
      body: fd
    });

    resetForm();
    loadPayments();
  };

  // ================= DELETE
  const deletePayment = async (id) => {
    await fetch(`http://localhost:5000/api/payments/${id}`, {
      method: "DELETE"
    });

    loadPayments();
  };

  // ================= EDIT
  const editPayment = (p) => {
    setForm(p);
    setEditId(p.id);
    setShowForm(true);
  };

  const resetForm = () => {
    setForm({
      title: "",
      clientName: "",
      projectName: "",
      milestoneName: "",
      totalAmount: "",
      paidAmount: "",
      pendingAmount: "",
      paymentDate: "",
      dueDate: ""
    });
    setFile(null);
    setEditId(null);
    setShowForm(false);
  };

  return (
    <div className="flex min-h-screen bg-gray-100">

      <Sidebar />

      <div className="flex-1 p-6">

        <button onClick={() => setShowForm(true)}>
          + Create Payment
        </button>

        {showForm && (
          <form onSubmit={savePayment} className="bg-white p-6 grid grid-cols-2 gap-4">

            <input name="title" value={form.title} onChange={handleChange} placeholder="Title" />
            <input name="clientName" value={form.clientName} onChange={handleChange} placeholder="Client" />
            <input name="projectName" value={form.projectName} onChange={handleChange} placeholder="Project" />
            <input name="milestoneName" value={form.milestoneName} onChange={handleChange} placeholder="Milestone" />
            <input name="totalAmount" value={form.totalAmount} onChange={handleChange} placeholder="Total" />
            <input name="paidAmount" value={form.paidAmount} onChange={handleChange} placeholder="Paid" />
            <input name="pendingAmount" value={form.pendingAmount} readOnly placeholder="Pending" />

            <input type="date" name="paymentDate" value={form.paymentDate} onChange={handleChange} />
            <input type="date" name="dueDate" value={form.dueDate} onChange={handleChange} />

            <button className="bg-green-500 text-white">
              {editId ? "Update" : "Save"}
            </button>

            <button type="button" onClick={resetForm}>
              Cancel
            </button>

          </form>
        )}

        {/* TABLE */}
        <table className="w-full bg-white mt-6">
          <thead>
            <tr>
              <th>Title</th>
              <th>Client</th>
              <th>Project</th>
              <th>Actions</th>
            </tr>
          </thead>

          <tbody>
            {payments.map(p => (
              <tr key={p.id}>
                <td>{p.title}</td>
                <td>{p.clientName}</td>
                <td>{p.projectName}</td>

                <td>
                  <button onClick={() => editPayment(p)}>Edit</button>
                  <button onClick={() => deletePayment(p.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>

        </table>

      </div>
    </div>
  );
}
